class App extends StatefulWidget {
  const App({Key key}) : super(key: key);

  @override
  State<StatefulWidget> createState() => _AppState();
}

class _AppState extends State<App>{

String text = '';
@override
void initState(){
    super.initState();
    setBiometricAuthStatus(); //Function to set the status of biometric authentication on app load
}

 void setBiometricAuthStatus() async{
   SharedPreferences pref = await SharedPreferences.getInstance();//Get instance for shared preferences
  String key = 'biometric_login';//Key name which is a string to store status
  try {
    var value =  await pref.getBool(key); //Check if there's any value stored in the shared preference for that key
      if (value != null){
        setState(() => text = 'You are already logged in'); //If a value exists, then set text to logged in.
      }else{
        setState(()=>text= 'Login with your biometric device');//else set the text to login with biometric device and change text color to red
        return;
        
      }
    
  } catch (e) {
    setState(() => text = 'Login with your biometric device');
  }
}

  @override
  Widget build(BuildContext context){ 
