//This function checks if biometrics are available and then asks for authentication.
  Future<void> _checkBiometricAuth()async{

    //Check for Biometric Authentication Support
    bool status = await checkSystemFeature(SystemFeature.biometry);
    print('Biometric support: $status');
    

   //If biometric authentication is available
   if (status){

     try {
       String authType;//Stores the type of authentication. Either faceID or fingerPrint
       LocalAuthenticationResponse response;

       switch(_platformCheck()) {
         case TargetPlatform.android:{//If android then set it to fingerprint
           authType = Biometrics.fingerprint;
           break;
         }
         case TargetPlatform.iOS: {//If iOS, then set it to FaceID
            authType = Biometrics.faceId;
           break;
         }
         default:
           authType = 'Password'; //Else store it as password.
       }

       response= await LocalAuthentication.authenticate(
        promptMessage: "Authenticate to continue", //Message to be displayed on authentication
        authenticationOptions : [authType],//Type of authentication
       );

       setState(() => text ='Login successful');
       SharedPreferences pref = await SharedPreferences.getInstance();//Get instance for shared preferences

       await pref.setString('biometric_login', 'true') ; //Set the value in shared preference to true
       setBiometricAuthStatus(); //Function call to check if there is any existing data stored in sharedPreference for biometric authentication
     } catch(e){
      setState(() => text ='Login failed');//If it's not successful, show a failed message.
       print('error : $e');
      }
    }
    else{
      setState(()=>text = 'Biometrics are not supported on this device'); //if it is not available then show the message that biometrics aren't available.
    }
  }

  TargetPlatform _platformCheck(){
     return TargetPlatform.platform;//Get the device platform in which app has been installed
  }

}